function sectionTabs(view){return `<div class="section-tabs"><button class="${view==='overview'?'active':''}" data-view="overview">Overview</button><button class="${view==='forms'?'active':''}" data-view="forms">Data Entry Forms</button><button class="${view==='reports'?'active':''}" data-view="reports">Reports</button></div>`}
function reportRecords(page,sources){return savedData().filter(record=>record.module===page&&sources.includes(record.form))}
