function sectionPage(page,view='overview'){if(view==='reports')return sectionReportsPage(page);if(['marketing','projectcosting','operations'].includes(page)){const html=lifecyclePage(page,view);return html.replace(/(<div class="section-tabs">[\s\S]*?)(<\/div>)/,`$1<button data-view="reports">Reports</button>$2`)}return `${sectionTabs(view)}${modulePage(page)}`}
function renderSectionReport(page,index){const definition=sectionReportDefinitions[page]?.[Number(index)];if(!definition)return;const rows=reportRecords(page,definition[1]),excluded=['module','form','createdAt','updatedAt'],columns=[...new Set(rows.flatMap(row=>Object.keys(row).filter(key=>!excluded.includes(key))))].slice(0,7),preview=document.getElementById('sectionReportPreview');preview.innerHTML=`<article class="card report-preview"><div class="card-title"><div><p class="section-eyebrow">GENERATED FROM SAVED RECORDS</p><h3>${definition[0]}</h3></div><div><span class="badge">${rows.length} records</span> <button class="action-btn" data-print-report>Print</button></div></div><p class="report-source">Sources: ${definition[1].join(', ')}</p><div class="table-wrap"><table><thead><tr>${(columns.length?columns:['Document Number']).map(column=>`<th>${column.toUpperCase()}</th>`).join('')}</tr></thead><tbody>${rows.length?rows.map(row=>`<tr>${columns.map(column=>`<td>${row[column]??'—'}</td>`).join('')}</tr>`).join(''):`<tr><td colspan="${Math.max(columns.length,1)}"><div class="empty-state">No saved records are available for this report.</div></td></tr>`}</tbody></table></div></article>`;preview.scrollIntoView({behavior:'smooth',block:'start'})}
const lifecyclePageReportsCore=lifecyclePage;
lifecyclePage=function(page,view='overview'){let html=lifecyclePageReportsCore(page,view);if(view!=='reports'&&!html.includes('data-view="reports"'))html=html.replace('Data Entry Forms</button></div>','Data Entry Forms</button><button data-view="reports">Reports</button></div>');return html};
sectionPage=function(page,view='overview'){if(view==='reports')return sectionReportsPage(page);if(['marketing','projectcosting','operations'].includes(page))return lifecyclePage(page,view);return `${sectionTabs(view)}${modulePage(page)}`};
