function decideOpportunity(documentNumber,decision){if(currentRole!=='Director Planning'){toast('Only Director Planning can make this decision');return}const saved=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]'),record=saved.find(r=>r.form==='Contract Opportunities'&&r['Document Number']===documentNumber);if(!record)return;record['Qualification decision']=decision;record['Decision authority']='Director Planning';record['Qualified by']='Director Planning';record['Qualification date']=new Date().toISOString().slice(0,10);record['Director Planning remarks']=decision==='Qualified'?'Approved for tendering and bidding assessment.':decision==='Returned for Clarification'?'Returned to opportunity owner for additional information.':'Opportunity does not meet current qualification criteria.';localStorage.setItem('mustaqeem-demo-records',JSON.stringify(saved));render('approvals');toast(`${documentNumber} marked ${decision}`)}
