function openForm(page=currentPage,key=''){const config=detailedForms[key]||formConfigs[page]||formConfigs.projects,doc=nextDocumentNumber(page,key),fields=[['Document Number','auto'],...config.fields.filter(f=>f[0].toLowerCase()!=='document number')],opportunities=qualifiedOpportunities();const form=document.getElementById('entryForm');form.dataset.formKey=key;form.dataset.counterKey=doc.counterKey;document.getElementById('formTitle').textContent=config.title;document.getElementById('formFields').innerHTML=fields.map((f,i)=>{const id=`field-${i}`,wide=['textarea','readonlyarea'].includes(f[1])?' wide':'';if(f[1]==='auto')return `<label>${f[0]}<input id="${id}" name="${f[0]}" type="text" value="${doc.number}" readonly required><small class="field-help">Automatically generated by MUSTAQEEM</small></label>`;if(f[1]==='opportunity-select')return `<label class="wide">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">${opportunities.length?'Select a qualified contract…':'No qualified contract available — qualify an opportunity first'}</option>${opportunities.map(r=>`<option value="${r['Document Number']}">${r['Document Number']} — ${r['Opportunity title']} — ${r['Prospective client']}</option>`).join('')}</select><small class="field-help">Only opportunities qualified by Director Planning are available.</small></label>`;if(f[1]==='readonly')return `<label>${f[0]}<input id="${id}" name="${f[0]}" type="text" readonly required></label>`;if(f[1]==='readonlyarea')return `<label class="wide">${f[0]}<textarea id="${id}" name="${f[0]}" rows="3" readonly required></textarea></label>`;if(f[1]==='image')return '<label class="wide company-logo-field">'+f[0]+'<input id="'+id+'" type="file" accept="image/png,image/jpeg" required><input id="companyLogoData" name="'+f[0]+'" type="hidden"><img id="companyLogoPreview" class="company-logo-preview hidden" alt="Company logo preview"><small class="field-help">PNG or JPEG company logo</small></label>';if(f[1]==='setup-select')return `<label class="${wide}">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">Select from setup…</option>${setupValues(f[2]).map(x=>`<option>${x}</option>`).join('')}</select><small class="field-help">Maintained under Settings &amp; Setups</small></label>`;if(f[1]==='select')return `<label class="${wide}">${f[0]}<select id="${id}" name="${f[0]}" required><option value="">Select…</option>${f[2].split('|').map(x=>`<option>${x}</option>`).join('')}</select></label>`;if(f[1]==='textarea')return `<label class="wide">${f[0]}<textarea id="${id}" name="${f[0]}" rows="3" required></textarea></label>`;return `<label class="${wide}">${f[0]}<input id="${id}" name="${f[0]}" type="${f[1]}" ${f[1]==='number'?'min="0" step="any"':''} required></label>`}).join('');if(key==='Chart of Accounts Setup'){document.getElementById('formFields').insertAdjacentHTML('afterbegin',`<section class="coa-import"><h3>Import Excel Chart of Accounts</h3><p>Upload the MUSTAQEEM workbook. The first worksheet must contain Account Code and Account Name columns.</p><input id="coaExcelUpload" type="file" accept=".xlsx,.xls"><span id="coaImportStatus" class="coa-import-status">No file selected.</span></section>`);bindCoaImport()}if(key==='Tender Register')bindTenderOpportunity();if(['Accounts Payable','Accounts Receivable','VAT & Tax Entries'].includes(key))bindVatCalculation();if(['Accounts Payable','Accounts Receivable'].includes(key))bindPartyMaster(key);if(key==='Company Setup')bindCompanyLogo();document.getElementById('formModal').classList.remove('hidden');setTimeout(()=>document.querySelector('#formFields input:not([readonly]), #formFields select')?.focus(),50)}
function bindCostScenarioCalculator(){const field=name=>document.querySelector(`[name="${name}"]`),quantity=field('Quantity'),unitCost=field('Unit cost (SAR)'),base=field('Base direct cost (SAR)'),revenue=field('Expected contract revenue (SAR)'),contract=field('Select qualified contract'),recommendedBid=field('Recommended bid value (SAR)');if(!quantity||!unitCost||!base)return;const scenarios={Worse:{pct:field('Worse adjustment (%)'),amount:field('Worse adjustment amount (SAR)'),cost:field('Worse estimated cost (SAR)'),profit:field('Worse forecast profit (SAR)'),margin:field('Worse forecast margin (%)'),direction:1,defaultPct:10},Normal:{pct:field('Normal adjustment (%)'),amount:field('Normal adjustment amount (SAR)'),cost:field('Normal estimated cost (SAR)'),profit:field('Normal forecast profit (SAR)'),margin:field('Normal forecast margin (%)'),direction:1,defaultPct:0},Good:{pct:field('Good efficiency saving (%)'),amount:field('Good saving amount (SAR)'),cost:field('Good estimated cost (SAR)'),profit:field('Good forecast profit (SAR)'),margin:field('Good forecast margin (%)'),direction:-1,defaultPct:8}};const number=input=>Number(input?.value||0),show=(input,value)=>{if(input)input.value=Number.isFinite(value)?value.toFixed(2):'0.00'};const calculateScenario=(scenario,changed='percentage')=>{const baseValue=number(base),revenueValue=number(revenue);let percentage=number(scenario.pct),amount=number(scenario.amount);if(changed==='amount'){percentage=baseValue?amount/baseValue*100:0;show(scenario.pct,percentage)}else{amount=baseValue*percentage/100;show(scenario.amount,amount)}const estimated=Math.max(0,baseValue+scenario.direction*amount),profit=revenueValue-estimated,margin=revenueValue?profit/revenueValue*100:0;show(scenario.cost,estimated);show(scenario.profit,profit);show(scenario.margin,margin)};const recalculateBase=()=>{show(base,number(quantity)*number(unitCost));Object.values(scenarios).forEach(s=>calculateScenario(s,'percentage'))};Object.values(scenarios).forEach(s=>{s.pct.value=s.defaultPct;s.pct.addEventListener('input',()=>calculateScenario(s,'percentage'));s.amount.addEventListener('input',()=>calculateScenario(s,'amount'))});quantity.addEventListener('input',recalculateBase);unitCost.addEventListener('input',recalculateBase);contract.addEventListener('change',()=>{const opportunity=qualifiedOpportunities().find(r=>r['Document Number']===contract.value);if(!opportunity)return;show(revenue,Number(opportunity['Estimated contract value (SAR)']||0));recommendedBid.value=Number(opportunity['Estimated contract value (SAR)']||0).toFixed(2);recalculateBase()});[['Worse adjustment (%)','WORSE CASE'],['Normal adjustment (%)','NORMAL CASE'],['Good efficiency saving (%)','GOOD CASE']].forEach(([name,title])=>{const label=field(name)?.closest('label');if(label){const heading=document.createElement('div');heading.className=`scenario-heading ${title.split(' ')[0].toLowerCase()}`;heading.textContent=title;label.before(heading)}});recalculateBase()}
