function bindProjectFormLink(key){if(key==='Awarded Projects')return;const original=document.querySelector('[name="Project"]');if(!original)return;const baselineStage=key==='Baseline Budgets',sources=baselineStage?awardedProjectRecords():baselineProjectRecords(),select=document.createElement('select');select.name='Project';select.required=true;select.innerHTML=`<option value="">${sources.length?'Select eligible project…':baselineStage?'No awarded project available':'No project with a baseline budget available'}</option>${sources.map(r=>{const id=baselineStage?r['Document Number']:r.Project,label=baselineStage?`${r['Project code']||r['Document Number']} — ${r['Project name']}`:`${r.Project} — Baseline ${r['Budget version']||r['Document Number']}`;return `<option value="${id}">${label}</option>`}).join('')}`;original.replaceWith(select);const label=select.closest('label');label?.insertAdjacentHTML('beforeend',`<small class="field-help">${baselineStage?'Only projects created from awarded contracts are available.':'Only projects with a saved baseline budget are available.'}</small>`);select.addEventListener('change',()=>{const baseline=baselineStage?null:sources.find(r=>r.Project===select.value),project=awardedProjectRecords().find(r=>r['Document Number']===(baselineStage?select.value:select.value));if(key==='Budget Revisions'&&baseline){const total=['Material budget (SAR)','Manpower budget (SAR)','Subcontractor budget (SAR)','Equipment budget (SAR)','Overhead budget (SAR)','Contingency (SAR)'].reduce((sum,name)=>sum+Number(baseline[name]||0),0);setFormValue('Original amount (SAR)',total)}if(key==='Project Profitability'){setFormValue('Contract revenue (SAR)',project?.['Contract value (SAR)']);if(baseline){const total=['Material budget (SAR)','Manpower budget (SAR)','Subcontractor budget (SAR)','Equipment budget (SAR)','Overhead budget (SAR)','Contingency (SAR)'].reduce((sum,name)=>sum+Number(baseline[name]||0),0);setFormValue('Forecast final cost (SAR)',total)}}})}
bindProjectFormLink=function(key){if(key==='Awarded Projects')return;const original=document.querySelector('[name="Project"]');if(!original)return;const sources=key==='Mobilization'?awardedProjectRecords():key==='Baseline Budgets'?mobilizationRecords():key==='Project Operations'?baselineProjectRecords():['Budget Revisions','Billing & Certification'].includes(key)?operationRecords():baselineProjectRecords(),projectId=r=>key==='Mobilization'?r['Document Number']:r.Project,select=document.createElement('select');select.name='Project';select.required=true;select.innerHTML=`<option value="">${sources.length?'Select eligible project…':'No eligible project is available from the preceding workflow stage'}</option>${sources.map(r=>{const id=projectId(r),project=awardedProjectRecords().find(p=>p['Document Number']===id);return `<option value="${id}">${project?.['Project code']||id} — ${project?.['Project name']||id}</option>`}).join('')}`;original.replaceWith(select);select.closest('label')?.insertAdjacentHTML('beforeend','<small class="field-help">Only projects completed in the preceding workflow stage are available.</small>');select.addEventListener('change',()=>{const source=sources.find(r=>projectId(r)===select.value),baseline=baselineProjectRecords().find(r=>r.Project===select.value),project=awardedProjectRecords().find(r=>r['Document Number']===select.value);if(key==='Project Operations')setFormValue('Baseline budget reference',source?.['Document Number']);if(key==='Billing & Certification')setFormValue('Operations reference',source?.['Document Number']);if(key==='Budget Revisions'&&baseline){const total=['Material budget (SAR)','Manpower budget (SAR)','Subcontractor budget (SAR)','Equipment budget (SAR)','Overhead budget (SAR)','Contingency (SAR)'].reduce((sum,name)=>sum+Number(baseline[name]||0),0);setFormValue('Original amount (SAR)',total)}if(key==='Project Profitability'){setFormValue('Contract revenue (SAR)',project?.['Contract value (SAR)']);if(baseline){const total=['Material budget (SAR)','Manpower budget (SAR)','Subcontractor budget (SAR)','Equipment budget (SAR)','Overhead budget (SAR)','Contingency (SAR)'].reduce((sum,name)=>sum+Number(baseline[name]||0),0);setFormValue('Forecast final cost (SAR)',total)}}})};
