function applyContractTypeCostRules(select){const opportunity=savedWorkflowRecords().find(r=>r.form==='Contract Opportunities'&&r['Document Number']===select?.value),material=document.querySelector('[name="Materials and consumables (SAR)"]'),label=material?.closest('label'),manpower=opportunity?.['Contract type']==='Manpower';if(!material||!label)return;label.hidden=manpower;material.disabled=manpower;if(manpower){material.value='0';material.dispatchEvent(new Event('input',{bubbles:true}))}label.querySelector('.field-help')?.remove();if(!manpower)label.insertAdjacentHTML('beforeend','<small class="field-help">Not applicable to Manpower contracts.</small>')}
