document.getElementById('signIn').onclick=()=>{currentRole=document.getElementById('loginRole').value;initializeCleanDataset();document.getElementById('login').classList.add('hidden');document.getElementById('app').classList.remove('hidden');document.querySelector('.side-footer b').textContent=currentRole==='Director Planning'?'Director Planning':'Marketing User';document.querySelector('.side-footer small').textContent=currentRole;document.querySelector('.side-footer>span').textContent=currentRole==='Director Planning'?'DP':'MU';updateRoleNavigation();refreshCompanySwitcher();render(currentRole==='Director Planning'?'approvals':'marketing','forms')};
