function setSidebarPinned(pinned){sidebarElement.classList.toggle('pinned',pinned);appElement.classList.toggle('sidebar-pinned',pinned);sidebarPin.classList.toggle('active',pinned);sidebarPin.setAttribute('aria-pressed',String(pinned));sidebarPin.title=pinned?'Use automatic sidebar':'Keep sidebar open';sidebarPin.setAttribute('aria-label',sidebarPin.title);const label=sidebarPin.querySelector('em');if(label)label.textContent=pinned?'Auto close':'Keep open';localStorage.setItem('mustaqeem-sidebar-pinned',String(pinned))}
