document.addEventListener('submit',e=>{if(e.target.id!=='entryForm'||!e.target.dataset.editDocument)return;e.preventDefault();e.stopImmediatePropagation();const documentNumber=e.target.dataset.editDocument,createdAt=e.target.dataset.editCreated,formKey=e.target.dataset.editForm,module=e.target.dataset.module||currentPage,saved=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]'),index=saved.findIndex(r=>r.module===module&&r.form===formKey&&r['Document Number']===documentNumber&&(!createdAt||r.createdAt===createdAt));if(index<0)return;const values=Object.fromEntries(new FormData(e.target));saved[index]={...saved[index],...values,'Document Number':documentNumber,updatedAt:new Date().toISOString()};localStorage.setItem('mustaqeem-demo-records',JSON.stringify(saved));closeForm();if(module==='marketing'&&currentMarketingRegister)renderMarketingRegister(currentMarketingRegister);else if(module==='projectcosting'&&currentProjectRegister)renderProjectRegister(currentProjectRegister);else if(currentModuleRegister.module===module&&currentModuleRegister.form===formKey)renderModuleRegister(module,formKey);else render(module,'forms');toast(`${documentNumber} updated successfully`)},true);
