document.addEventListener('click',e=>{const back=e.target.closest('[data-project-register-back]'),newButton=e.target.closest('[data-project-register-new]'),card=e.target.closest('[data-form-card]');if(back){e.stopImmediatePropagation();currentProjectRegister='';updateProjectSubnav('');render('projectcosting','forms');return}if(newButton){e.stopImmediatePropagation();openForm('projectcosting',newButton.dataset.projectRegisterNew);return}if(card&&currentPage==='projectcosting'){e.stopImmediatePropagation();renderProjectRegister(card.dataset.formKey)}},true);
document.addEventListener('click',e=>{if(e.target.closest('[data-page], [data-register-back]'))updateMarketingSubnav('');if(e.target.closest('[data-page], [data-project-register-back]'))updateProjectSubnav('');if(e.target.closest('[data-page], [data-module-register-back]'))updateModuleSubnav('')},true);
document.addEventListener('click',e=>{const back=e.target.closest('[data-register-back]'),newButton=e.target.closest('[data-register-new]'),card=e.target.closest('[data-form-card]');if(back){e.stopImmediatePropagation();currentMarketingRegister='';render('marketing','forms');return}if(newButton){e.stopImmediatePropagation();const key=newButton.dataset.registerNew;openForm('marketing',marketingStoredForm(key));return}if(card&&currentPage==='marketing'){e.stopImmediatePropagation();renderMarketingRegister(card.dataset.formKey)}},true);
document.addEventListener('click',e=>{if(currentRole==='User'&&currentPage==='marketing'&&e.target.closest('[data-new-form]')){e.stopImmediatePropagation();openForm('marketing','Contract Opportunities')}},true);
document.addEventListener('click',e=>{const decision=e.target.closest('[data-qualify="Qualified"]');if(decision)setTimeout(()=>ensureTenderHandoff(decision.dataset.opportunity),0)});
document.addEventListener('click',e=>{const decision=e.target.closest('[data-qualify]');if(decision){decideOpportunity(decision.dataset.opportunity,decision.dataset.qualify);return}const n=e.target.closest('[data-page]');if(n)render(n.dataset.page);const l=e.target.closest('[data-page-link]');if(l)render(l.dataset.pageLink);const view=e.target.closest('[data-view]');if(view)render(currentPage,view.dataset.view);const formCard=e.target.closest('[data-form-card]');if(formCard)openForm(currentPage,formCard.dataset.formKey);else if(e.target.closest('[data-new-form]'))openForm();const shortlist=e.target.closest('[data-shortlist]');if(shortlist){const next=shortlist.getAttribute('aria-pressed')!=='true';document.querySelector('.pipeline-table-host').innerHTML=opportunityPipeline(next)}const period=e.target.closest('.period button');if(period){document.querySelectorAll('.period button').forEach(x=>x.classList.remove('active'));period.classList.add('active');toast(`Period changed to ${period.textContent}`)}const action=e.target.closest('[data-action]');if(action)toast();if(e.target.closest('[data-close-modal]'))closeForm();if(e.target.closest('[data-print-report]'))window.print()});
document.addEventListener('change',e=>{if(e.target.matches('[data-project-filter]'))document.querySelector('.portfolio-table-host').innerHTML=projectPortfolio(e.target.value)});
document.addEventListener('input',e=>{if(e.target.matches('.filters input')){const q=e.target.value.trim().toLowerCase();document.querySelectorAll('.module-grid .module-card').forEach(card=>card.hidden=Boolean(q)&&!card.textContent.toLowerCase().includes(q))}});
function reportPreview(record){content.innerHTML=`<div class="hero-row"><div><p class="section-eyebrow">GENERATED MANAGEMENT REPORT</p><h1>${record.Report||'Management Report'}</h1><p>${record['Period from']||'01-Jul-2026'} to ${record['Period to']||'31-Jul-2026'} • ${record.Project||'All Projects'}</p></div><div class="page-tools"><button data-page="reports">← Reports</button><button class="action-btn primary-small" data-print-report>Print / Save PDF</button></div></div><div class="kpi-grid">${kpi('Contract Value','SAR 48.6M','↗','12.6%')}${kpi('Revenue','SAR 28.4M','◫','9.2%')}${kpi('Actual Cost','SAR 20.9M','↘','5.8%')}${kpi('Forecast Margin','18.7%','⌁','2.1%')}</div><article class="card"><div class="card-title"><h3>Project performance summary</h3><span class="badge">Sample data</span></div>${projectTable(projects)}</article>`}
document.addEventListener('submit',e=>{if(e.target.id!=='entryForm'||e.target.dataset.formKey!=='Contract Opportunities')return;[['Qualification decision','Pending Director Planning Review'],['Decision authority','Director Planning'],['Director Planning remarks','Awaiting Director Planning review.']].forEach(([name,value])=>{const input=document.createElement('input');input.type='hidden';input.name=name;input.value=value;e.target.appendChild(input)})},true);
document.addEventListener('submit',e=>{if(e.target.id!=='entryForm'||e.target.dataset.formKey!=='Award / Loss Register')return;const outcome=Object.fromEntries(new FormData(e.target));setTimeout(()=>ensureAwardProjectHandoff(outcome),0)},true);
document.getElementById('entryForm').addEventListener('submit',e=>{e.preventDefault();const formKey=e.target.dataset.formKey,record=Object.fromEntries(new FormData(e.target)),counterKey=e.target.dataset.counterKey,page=e.target.dataset.module||currentPage;const saved=JSON.parse(localStorage.getItem('mustaqeem-demo-records')||'[]');saved.push({module:page,form:formKey,createdAt:new Date().toISOString(),...record});localStorage.setItem('mustaqeem-demo-records',JSON.stringify(saved));if(counterKey)localStorage.setItem(counterKey,String(Number(localStorage.getItem(counterKey)||1)+1));const isReport=page==='reports';closeForm();delete e.target.dataset.module;if(isReport){reportPreview(record);toast('Report generated successfully')}else if(page==='settings'){toast(`Record ${record['Document Number']} saved successfully`)}else{render(page,['marketing','projectcosting','operations'].includes(page)?'forms':'overview');toast(formKey==='Contract Opportunities'?`Record ${record['Document Number']} submitted for Director Planning qualification`:`Record ${record['Document Number']} saved successfully`)}});
document.getElementById('entryForm').addEventListener('submit',e=>{if(e.target.dataset.formKey==='Company Setup')setTimeout(refreshCompanySwitcher,0)});
document.getElementById('entryForm').addEventListener('submit',e=>{const submitted=e.target.dataset.formKey,register=currentMarketingRegister;if(register&&marketingStoredForm(register)===submitted)setTimeout(()=>renderMarketingRegister(register),0)});
document.getElementById('entryForm').addEventListener('submit',e=>{const submitted=e.target.dataset.formKey,register=currentProjectRegister;if(register===submitted)setTimeout(()=>renderProjectRegister(register),0)});
document.getElementById('entryForm').addEventListener('submit',e=>{const submitted=e.target.dataset.formKey,{module,form}=currentModuleRegister;if(module&&form===submitted)setTimeout(()=>renderModuleRegister(module,form),0)});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeForm()});
